import React, { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./AddEmployee.css";

const AddEmployee = () => {
  const navigate = useNavigate();
  const { id } = useParams(); // edit mode detection

  const [employee, setEmployee] = useState({
    id: "",
    name: "",
    email: "",
    empId: "",
    dob: "",
    gender: "",
    maritalStatus: "",
    designation: "",
    department: "",
    salary: "",
    role: "",
  });

  /* Load employee data for Edit */
  useEffect(() => {
    if (id) {
      const storedEmployees =
        JSON.parse(localStorage.getItem("employees")) || [];

      const empToEdit = storedEmployees.find(
        (emp) => emp.id.toString() === id
      );

      if (empToEdit) {
        setEmployee(empToEdit);
      }
    }
  }, [id]);

  /* Handle input change */
  const handleChange = (e) => {
    const { name, value } = e.target;

    setEmployee({
      ...employee,
      [name]: value,
    });
  };

  /* Handle submit */
  const handleSubmit = (e) => {
    e.preventDefault();

    const storedEmployees =
      JSON.parse(localStorage.getItem("employees")) || [];

    if (id) {
      // UPDATE employee
      const updatedEmployees = storedEmployees.map((emp) =>
        emp.id.toString() === id ? employee : emp
      );

      localStorage.setItem(
        "employees",
        JSON.stringify(updatedEmployees)
      );
    } else {
      // ADD employee
      const newEmployee = {
        ...employee,
        id: Date.now(),
      };

      storedEmployees.push(newEmployee);

      localStorage.setItem(
        "employees",
        JSON.stringify(storedEmployees)
      );
    }

    navigate("/dashboard/employee-details");
  };

  return (
    <div className="add-employee-page">
      <h2>{id ? "Edit Employee" : "Add New Employee"}</h2>

      <form className="add-employee-form" onSubmit={handleSubmit}>
        {/* Row 1 */}
        <div className="form-row">
          <div className="form-group">
            <label>Name</label>
            <input
              name="name"
              value={employee.name}
              onChange={handleChange}
              required
            />
          </div>

          <div className="form-group">
            <label>Email</label>
            <input
              name="email"
              type="email"
              value={employee.email}
              onChange={handleChange}
              required
            />
          </div>
        </div>

        {/* Row 2 */}
        <div className="form-row">
          <div className="form-group">
            <label>Employee ID</label>
            <input
              name="empId"
              value={employee.empId}
              onChange={handleChange}
              required
            />
          </div>

          <div className="form-group">
            <label>Date of Birth</label>
            <input
              name="dob"
              type="date"
              value={employee.dob}
              onChange={handleChange}
              required
            />
          </div>
        </div>

        {/* Row 3 */}
        <div className="form-row">
          <div className="form-group">
            <label>Gender</label>
            <select
              name="gender"
              value={employee.gender}
              onChange={handleChange}
              required
            >
              <option value="">Select</option>
              <option>Male</option>
              <option>Female</option>
            </select>
          </div>

          <div className="form-group">
            <label>Marital Status</label>
            <select
              name="maritalStatus"
              value={employee.maritalStatus}
              onChange={handleChange}
            >
              <option value="">Select</option>
              <option>Single</option>
              <option>Married</option>
            </select>
          </div>
        </div>

        {/* Row 4 */}
        <div className="form-row">
          <div className="form-group">
            <label>Designation</label>
            <input
              name="designation"
              value={employee.designation}
              onChange={handleChange}
            />
          </div>

          <div className="form-group">
            <label>Department</label>
            <select
              name="department"
              value={employee.department}
              onChange={handleChange}
              required
            >
              <option value="">Select</option>
              <option>IT</option>
              <option>Database</option>
              <option>Logistic</option>
            </select>
          </div>
        </div>

        {/* Row 5 */}
        <div className="form-row">
          <div className="form-group">
            <label>Salary</label>
            <input
              name="salary"
              type="number"
              value={employee.salary}
              onChange={handleChange}
              required
            />
          </div>

          <div className="form-group">
            <label>Role</label>
            <select
              name="role"
              value={employee.role}
              onChange={handleChange}
              required
            >
              <option value="">Select</option>
              <option>Admin</option>
              <option>Employee</option>
            </select>
          </div>
        </div>

        <button type="submit" className="submit-btn">
          {id ? "Update Employee" : "Add Employee"}
        </button>
      </form>
    </div>
  );
};

export default AddEmployee;
